import re
from typing import List, Tuple, Optional

# Define token specifications using regular expressions
# Each tuple: (token_type, regex_pattern)
TOKEN_SPECIFICATIONS = [
 ('KEYWORD', r'\b(if|else|while|return|int|float|void|for|break|continue)\b'),
 ('IDENTIFIER', r'[a-zA-Z][a-zA-Z0-9]*'),
 ('REAL_NUMBER', r'[0-9]+\.[0-9]+'),
 ('INTEGER', r'[0-9]+'),
 ('STRING', r'"[^"\n]*"'),
 ('OPERATOR', r'<=?|>=?|==|!=|\+|\-|\*|\/'),
 ('PUNCTUATION', r'[;,\(\)\{\}]'),
 ('COMMENT_SINGLE', r'//[^\n]*'),
 ('COMMENT_MULTI', r'/\*[\s\S]*?\*/'),
 ('WHITESPACE', r'\s+'),
]

class TokenSpecification:
 """Represents a token specification with pattern and type."""

 def __init__(self, token_type: str, pattern: str):
 self.token_type = token_type
 self.pattern = pattern
 self.regex = re.compile(pattern)

 def match(self, text: str, pos: int) -> Optional[re.Match]:
 """Attempt to match the pattern at given position."""
 match = self.regex.match(text, pos)
 if match and match.start() == pos:
 return match
 return None

class LexicalAnalyzer:
 """Lexical analyzer that recognizes tokens based on specifications."""

 def __init__(self, specifications: List[Tuple[str, str]]):
 # Create ordered list of token specifications
 self.token_specs = [
 TokenSpecification(tok_type, pattern) 
 for tok_type, pattern in specifications
 ]

 def tokenize(self, source_code: str) -> List[Tuple[str, str]]:
 """Convert source code into list of tokens."""
 tokens = []
 pos = 0

 while pos < len(source_code):
 matched = False

 # Try each token specification in order (priority)
 for spec in self.token_specs:
 match = spec.match(source_code, pos)

 if match:
 lexeme = match.group()
 match_length = match.end() - match.start()

 # Skip whitespace and comments
 if spec.token_type not in ('WHITESPACE', 'COMMENT_SINGLE', 'COMMENT_MULTI'):
 if match_length > 0:
 tokens.append((spec.token_type, lexeme))

 pos = match.end()
 matched = True
 break # Longest match - exit after first match

 if not matched:
 raise LexicalError(f"Illegal character '{source_code[pos]}' at position {pos}")

 return tokens


# Demonstration
if __name__ == "__main__":
 # Sample source code
 source = """
 int x = 42;
 float pi = 3.14159;
 if (x > 0) {
 return x * 2;
 }
 // This is a comment
 """

 # Create lexical analyzer with our specifications
 lexer = LexicalAnalyzer(TOKEN_SPECIFICATIONS)

 # Tokenize the source code
 try:
 tokens = lexer.tokenize(source)
 print("Tokens recognized:")
 print("-" * 40)
 for token_type, lexeme in tokens:
 print(f"{token_type:15} : {lexeme}")
 except LexicalError as e:
 print(f"Lexical Error: {e}")

class LexicalError(Exception):
 """Exception raised for lexical errors."""
 pass

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define MAX_TOKEN_LENGTH 100
#define MAX_TOKENS 1000

// Token types enumeration
typedef enum {
 TOKEN_KEYWORD,
 TOKEN_IDENTIFIER,
 TOKEN_INTEGER,
 TOKEN_REAL,
 TOKEN_STRING,
 TOKEN_OPERATOR,
 TOKEN_PUNCTUATION,
 TOKEN_UNKNOWN,
 TOKEN_EOF
} TokenType;

// Token structure
typedef struct {
 TokenType type;
 char lexeme[MAX_TOKEN_LENGTH];
 int line;
} Token;

// Token type names for display
const char* token_type_names[] = {
 "KEYWORD", "IDENTIFIER", "INTEGER", "REAL", 
 "STRING", "OPERATOR", "PUNCTUATION", "UNKNOWN", "EOF"
};

// Keyword list
const char* keywords[] = {
 "if", "else", "while", "return", "int", "float", 
 "void", "for", "break", "continue", NULL
};

// Input buffer
char input[10000];
int input_pos = 0;
int input_len = 0;
int current_line = 1;

// Function prototypes
Token get_next_token(void);
void skip_whitespace(void);
int is_keyword(const char* str);
int is_letter(char c);
int is_digit(char c);

// Skip whitespace and comments
void skip_whitespace(void) {
 while (input_pos < input_len) {
 // Skip whitespace
 if (isspace(input[input_pos])) {
 if (input[input_pos] == '\n') {
 current_line++;
 }
 input_pos++;
 }
 // Skip single-line comments
 else if (input[input_pos] == '/' && input[input_pos + 1] == '/') {
 while (input_pos < input_len && input[input_pos] != '\n') {
 input_pos++;
 }
 }
 // Skip multi-line comments
 else if (input[input_pos] == '/' && input[input_pos + 1] == '*') {
 input_pos += 2;
 while (input_pos < input_len - 1) {
 if (input[input_pos] == '\n') current_line++;
 if (input[input_pos] == '*' && input[input_pos + 1] == '/') {
 input_pos += 2;
 break;
 }
 input_pos++;
 }
 }
 else {
 break; // Non-whitespace character found
 }
 }
}

// Check if string is a keyword
int is_keyword(const char* str) {
 for (int i = 0; keywords[i] != NULL; i++) {
 if (strcmp(str, keywords[i]) == 0) {
 return 1;
 }
 }
 return 0;
}

// Check if character is a letter
int is_letter(char c) {
 return (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || c == '_';
}

// Check if character is a digit
int is_digit(char c) {
 return (c >= '0' && c <= '9');
}

// Read identifier or keyword
Token read_identifier(void) {
 Token token;
 int i = 0;

 token.type = TOKEN_IDENTIFIER;
 token.lexeme[i++] = input[input_pos++];

 while (input_pos < input_len && (is_letter(input[input_pos]) || 
 is_digit(input[input_pos]))) {
 if (i < MAX_TOKEN_LENGTH - 1) {
 token.lexeme[i++] = input[input_pos++];
 } else {
 input_pos++; // Skip excess characters
 }
 }
 token.lexeme[i] = '\0';
 token.line = current_line;

 // Check if it's a keyword
 if (is_keyword(token.lexeme)) {
 token.type = TOKEN_KEYWORD;
 }

 return token;
}

// Read integer or real number
Token read_number(void) {
 Token token;
 int i = 0;
 int has_dot = 0;

 token.type = TOKEN_INTEGER;
 while (input_pos < input_len && is_digit(input[input_pos])) {
 if (i < MAX_TOKEN_LENGTH - 1) {
 token.lexeme[i++] = input[input_pos++];
 } else {
 input_pos++;
 }
 }

 // Check for decimal point (real number)
 if (input_pos < input_len && input[input_pos] == '.') {
 token.type = TOKEN_REAL;
 if (i < MAX_TOKEN_LENGTH - 1) {
 token.lexeme[i++] = input[input_pos++];
 }
 // Read fractional part
 while (input_pos < input_len && is_digit(input[input_pos])) {
 if (i < MAX_TOKEN_LENGTH - 1) {
 token.lexeme[i++] = input[input_pos++];
 } else {
 input_pos++;
 }
 }
 }

 token.lexeme[i] = '\0';
 token.line = current_line;
 return token;
}

// Read string literal
Token read_string(void) {
 Token token;
 int i = 0;

 token.type = TOKEN_STRING;
 input_pos++; // Skip opening quote

 while (input_pos < input_len && input[input_pos] != '"' && 
 input[input_pos] != '\n') {
 if (i < MAX_TOKEN_LENGTH - 1) {
 // Handle escape sequences
 if (input[input_pos] == '\\' && input_pos + 1 < input_len) {
 token.lexeme[i++] = input[input_pos++];
 }
 token.lexeme[i++] = input[input_pos++];
 } else {
 input_pos++;
 }
 }

 if (input[input_pos] == '"') {
 input_pos++; // Skip closing quote
 }
 token.lexeme[i] = '\0';
 token.line = current_line;
 return token;
}

// Get next token from input
Token get_next_token(void) {
 Token token;

 // Skip whitespace and comments first
 skip_whitespace();

 // Check for end of input
 if (input_pos >= input_len) {
 token.type = TOKEN_EOF;
 strcpy(token.lexeme, "");
 token.line = current_line;
 return token;
 }

 char c = input[input_pos];

 // Identifier or keyword: starts with letter
 if (is_letter(c)) {
 return read_identifier();
 }

 // Number: starts with digit
 if (is_digit(c)) {
 return read_number();
 }

 // String literal
 if (c == '"') {
 return read_string();
 }

 // Operators and punctuation
 // Check for two-character operators first
 if (input_pos + 1 < input_len) {
 char two_char[3] = {c, input[input_pos + 1], '\0'};
 if (strcmp(two_char, "<=") == 0 || strcmp(two_char, ">=") == 0 ||
 strcmp(two_char, "==") == 0 || strcmp(two_char, "!=") == 0) {
 token.type = TOKEN_OPERATOR;
 strcpy(token.lexeme, two_char);
 token.line = current_line;
 input_pos += 2;
 return token;
 }
 }

 // Single-character operators
 if (strchr("+-*/<>=!%", c)) {
 token.type = TOKEN_OPERATOR;
 token.lexeme[0] = c;
 token.lexeme[1] = '\0';
 token.line = current_line;
 input_pos++;
 return token;
 }

 // Punctuation
 if (strchr(";,(){}[]", c)) {
 token.type = TOKEN_PUNCTUATION;
 token.lexeme[0] = c;
 token.lexeme[1] = '\0';
 token.line = current_line;
 input_pos++;
 return token;
 }

 // Unknown character
 token.type = TOKEN_UNKNOWN;
 token.lexeme[0] = c;
 token.lexeme[1] = '\0';
 token.line = current_line;
 input_pos++;
 return token;
}

// Main function for demonstration
int main(void) {
 // Sample source code
 const char* sample = 
 "int main() {\n"
 " int x = 42;\n"
 " float pi = 3.14159;\n"
 " if (x > 0) {\n"
 " return x * 2;\n"
 " }\n"
 "}\n"
 "// End of program";

 // Copy to input buffer
 strcpy(input, sample);
 input_len = strlen(input);
 input_pos = 0;
 current_line = 1;

 printf("=== Token Specification Demo in C ===\n\n");
 printf("Source Code:\n%s\n\n", sample);
 printf("Tokens Recognized:\n");
 printf("----------------------------------------\n");

 // Get all tokens
 Token token;
 while ((token = get_next_token()).type != TOKEN_EOF) {
 printf("Line %2d: %-12s : %s\n", 
 token.line, 
 token_type_names[token.type], 
 token.lexeme);
 }
 printf("Line %2d: %-12s\n", token.line, token_type_names[token.type]);

 return 0;
}
